<template>
  <div class="container-fluid">
    <div class="row my-2 justify-content-center">
      <div id="boxLeft" class="my-2" style="width:1160px; height:300px;"></div>
      <div id="boxRight" class="my-2" style="width:1160px; height:620px;"></div>
    </div>
  </div>
</template>

<script>
import { InputHandler } from "../../../classes/InputHandler.js";

export default {
  data() {
    return {
      bL: null,
      bR: null,
      IH: null,
      sliders: {},
      panelButtons: {},
      gButtons: {},
      resultantButtons: {}
    };
  },
  mounted() {
    this.initBoards();
  },
  beforeDestroy() {
    if (this.bL) JXG.JSXGraph.freeBoard(this.bL);
    if (this.bR) JXG.JSXGraph.freeBoard(this.bR);
  },
  methods: {
    setBtnActive(btn, active) {
      if (!btn || !btn.rendNodeButton) return;
      btn.rendNodeButton.classList.toggle("btn-warning", active);
    },
    updatePanelButtonStyles() {
      if (!this.IH) return;
      const selected = this.IH.values.panel;
      Object.keys(this.panelButtons).forEach(key => {
        this.setBtnActive(this.panelButtons[key], key === selected);
      });
    },
    updateGButtonStyles() {
      if (!this.IH) return;
      const selected = this.IH.values.g;
      Object.keys(this.gButtons).forEach(key => {
        this.setBtnActive(this.gButtons[key], key === selected);
      });
    },
    updateResultantButtonStyles() {
      if (!this.IH) return;
      const selected = this.IH.values.resultant;
      Object.keys(this.resultantButtons).forEach(key => {
        this.setBtnActive(this.resultantButtons[key], key === selected);
      });
    },
    initBoards() {
      const bL = JXG.JSXGraph.initBoard("boxLeft", {
        boundingbox: [-15, 8, 15, -19],
        keepAspectRatio: false,
        showCopyright: false,
        showNavigation: false,
        showZoom: false,
        pan: { enabled: false },
        zoom: { wheel: false },
        axis: false
      });
      bL.resizeContainer(1160, 300);

      const bR = JXG.JSXGraph.initBoard("boxRight", {
        boundingbox: [-16, 11.5, 16, -13.5],
        keepAspectRatio: false,
        showCopyright: false,
        showNavigation: false,
        showZoom: false,
        pan: { enabled: false },
        zoom: { wheel: false },
        axis: false
      });
      bR.resizeContainer(1160, 620);

      this.bL = bL;
      this.bR = bR;

      const values = {
        panel: "flat_const",
        g: "9.8",
        resultant: "off"
      };
      const IH = new InputHandler(bL, -4.0, 6.8, -1.8, 8.8, 16, values, 0);
      this.IH = IH;
      IH.buttonsToToggle.panel = {};
      IH.buttonsToToggle.g = {};
      IH.buttonsToToggle.resultant = {};

      const panelY = 6.8;
      const panelDefs = [
        { key: "flat_const", label: "Flat Plate + Constant Width", state: 0, x: -14.6 },
        { key: "curved_const", label: "Curved Plate + Constant Width", state: 1, x: -6.2 },
        { key: "flat_varied", label: "Flat Plate + Varied Width", state: 2, x: 2.5 }
      ];
      panelDefs.forEach(def => {
        const btn = bL.create(
          "button",
          [
            def.x,
            panelY,
            def.label,
            () => {
              IH.values.panel = def.key;
              IH.updateState(def.state);
              this.updatePanelButtonStyles();
              this.updateGButtonStyles();
              this.refreshBoards();
            }
          ],
          { fixed: true }
        );
        btn.rendNodeButton.classList.add("btn-primary");
        this.panelButtons[def.key] = btn;
      });

      const sliders = {};
      this.sliders = sliders;
      [
        ["rho", "Liquid Density (×10^3)", -4.0, true, [0.5, 1.1, 2], [0, 1, 2], "#1f77b4"],
        ["zA", "z_A", -8.6, true, [0, 5.8, 20], [0, 1, 2], "#1f77b4"],
        ["theta", "Angle of Plate  θ (°)", -13.2, true, [0, 44, 90], [0, 1, 2], "#1f77b4"]
      ].forEach(def => IH.generate(def, sliders));

      const gY = -10.8;
      bL.create("text", [-14.2, gY, "g:"], {
        fontSize: 16,
        fixed: true
      });
      const gDefs = [
        { key: "0", label: "0", x: -12.7 },
        { key: "9.8", label: "9.8", x: -11.2 },
        { key: "10", label: "10", x: -9.6 }
      ];
      gDefs.forEach(def => {
        const btn = bL.create(
          "button",
          [
            def.x,
            gY,
            def.label,
            () => {
              IH.values.g = def.key;
              this.updateGButtonStyles();
              this.refreshBoards();
            }
          ],
          { fixed: true }
        );
        btn.rendNodeButton.classList.add("btn-primary");
        this.gButtons[def.key] = btn;
      });

      const rY = -15.6;
      bL.create("text", [-14.2, rY, "Resultant:"], {
        fontSize: 16,
        fixed: true
      });
      const rDefs = [
        { key: "off", label: "Off", x: -11.5 },
        { key: "on", label: "On", x: -9.8 }
      ];
      rDefs.forEach(def => {
        const btn = bL.create(
          "button",
          [
            def.x,
            rY,
            def.label,
            () => {
              IH.values.resultant = def.key;
              this.updateResultantButtonStyles();
              this.refreshBoards();
            }
          ],
          { fixed: true }
        );
        btn.rendNodeButton.classList.add("btn-primary");
        this.resultantButtons[def.key] = btn;
      });

      ["rho", "zA", "theta"].forEach(key => {
        sliders[key].on("drag", () => this.refreshBoards());
      });

      IH.setCallback(() => {
        this.updatePanelButtonStyles();
        this.updateGButtonStyles();
        this.updateResultantButtonStyles();
        this.refreshBoards();
      });

      IH.updateState(0);
      this.updatePanelButtonStyles();
      this.updateGButtonStyles();
      this.updateResultantButtonStyles();
      IH.fixTextAlignment();
      IH.toggleButtons();
      this.refreshBoards();
    },
    refreshBoards() {
      if (!this.bR || !this.IH || !this.sliders.rho) return;
      this.drawModel();
      this.bL.fullUpdate();
      this.bR.fullUpdate();
    },
    drawModel() {
      const panel = this.IH.values.panel;
      const resultant = this.IH.values.resultant;
      const rho = Number(this.sliders.rho.Value());
      const zA = Number(this.sliders.zA.Value());
      const theta = Number(this.sliders.theta.Value());

      this.bR.suspendUpdate();
      this.bR.removeObject(this.bR.objectsList.slice());
      const rad = (theta * Math.PI) / 180;
      const rhoSI = rho * 1000;
      const gVal = Number(this.IH.values.g);
      const OX = -13.4;
      const OY = 8.2;
      const shiftZ = 0.18 * zA;
      const arrowScale = 0.9 * rho;
      const arrowCount = 12;
      const gFactor = Number(this.IH.values.g) / 9.8;

      const drawLeftAxes = () => {
        this.bR.create("arrow", [[OX, OY], [OX + 11.5, OY]], {
          strokeColor: "#111",
          fillColor: "#111",
          strokeWidth: 2,
          fixed: true
        });
        this.bR.create("arrow", [[OX, OY], [OX, OY - 10.5]], {
          strokeColor: "#111",
          fillColor: "#111",
          strokeWidth: 2,
          fixed: true
        });
        this.bR.create("point", [OX, OY], {
          size: 6,
          strokeColor: "#111",
          fillColor: "white",
          fixed: true,
          name: ""
        });

        this.bR.create("text", [OX + 11.9, OY + 0.5, "x"], { fontSize: 24, fixed: true });
        this.bR.create("text", [OX - 0.6, OY + 0.5, "y"], { fontSize: 24, fixed: true });
        this.bR.create("text", [OX - 0.6, OY - 11.5, "z"], { fontSize: 24, fixed: true });
      };

      const drawRightAxes = () => {
        const rx = 5.1;
        const ry = 1.5;
        this.bR.create("arrow", [[rx, ry], [10.8, ry - 1.4]], {
          strokeColor: "#111",
          fillColor: "#111",
          strokeWidth: 2,
          fixed: true
        });
        this.bR.create("arrow", [[rx, ry], [3.4, ry - 2.4]], {
          strokeColor: "#111",
          fillColor: "#111",
          strokeWidth: 2,
          fixed: true
        });
        this.bR.create("arrow", [[rx, ry], [4.5, ry - 5.6]], {
          strokeColor: "#111",
          fillColor: "#111",
          strokeWidth: 2,
          fixed: true
        });
        this.bR.create("text", [11.1, ry - 1.7, "x"], { fontSize: 24, fixed: true });
        this.bR.create("text", [4.3, ry - 6.2, "z"], { fontSize: 24, fixed: true });
      };

      drawLeftAxes();
      drawRightAxes();

      if (panel === "flat_const") {
        const A = [OX, OY - shiftZ];
        const L = 12;
        const B = [A[0] + L * Math.cos(rad), A[1] - L * Math.sin(rad)];
        const C = [(A[0] + B[0]) / 2, (A[1] + B[1]) / 2];

        this.bR.create("segment", [A, B], {
          strokeColor: "#4f5cff",
          strokeWidth: 4,
          fixed: true
        });
        this.bR.create("text", [A[0] - 0.7, A[1] - 0.3, "A"], { fontSize: 24, fixed: true });
        this.bR.create("text", [C[0] - 0.4, C[1] - 0.9, "C"], { fontSize: 24, fixed: true });

        const t2 = [Math.cos(rad), -Math.sin(rad)];
        const n2 = [-t2[1], t2[0]];
        const pressureDir2 = [-n2[0], -n2[1]];

        if (resultant === "off") {
          for (let i = 0; i < arrowCount; i++) {
            const t = (i + 0.2) / arrowCount;
            const px = A[0] + t * (B[0] - A[0]);
            const py = A[1] + t * (B[1] - A[1]);
            const len = (0.8 + 0.22 * i) * arrowScale;
            this.bR.create("arrow", [[px - len * pressureDir2[0], py - len * pressureDir2[1]], [px, py]], {
              strokeColor: "red",
              fillColor: "red",
              strokeWidth: 2,
              fixed: true
            });
          }
        }

        const cx = 8.1;
        const cy = -0.2 - 0.15 * shiftZ;
        const ux = 5.5 * Math.cos(rad);
        const uy = -5.5 * Math.sin(rad);
        const wx = -1.9;
        const wy = 2.2;

        const q1 = this.bR.create("point", [cx - ux / 2, cy - uy / 2], { visible: false, fixed: true, name: "" });
        const q2 = this.bR.create("point", [cx + ux / 2, cy + uy / 2], { visible: false, fixed: true, name: "" });
        const q3 = this.bR.create("point", [cx + ux / 2 + wx, cy + uy / 2 + wy], { visible: false, fixed: true, name: "" });
        const q4 = this.bR.create("point", [cx - ux / 2 + wx, cy - uy / 2 + wy], { visible: false, fixed: true, name: "" });

        this.bR.create("polygon", [q1, q2, q3, q4], {
          fillColor: "#d8fbff",
          fillOpacity: 0.7,
          fixed: true,
          borders: {
            strokeColor: "#222",
            strokeWidth: 2
          },
          vertices: { visible: false }
        });

        const t3x = ux;
        const t3y = uy;
        const n3norm = Math.hypot(-t3y, t3x) || 1;
        const n3 = [(-t3y / n3norm) * 1.15, (t3x / n3norm) * 1.15];
        const pressureDir3 = [-n3[0], -n3[1]];

        if (resultant === "off") {
          for (let i = 0; i < arrowCount; i++) {
            const t = (i + 0.2) / arrowCount;
            const px = cx - ux / 2 + wx * 0.5 + t * ux;
            const py = cy - uy / 2 + wy * 0.5 + t * uy;
            const len = (0.55 + 0.12 * i) * arrowScale;
            this.bR.create("arrow", [[px - len * pressureDir3[0], py - len * pressureDir3[1]], [px, py]], {
              strokeColor: "red",
              fillColor: "red",
              strokeWidth: 2,
              fixed: true
            });
          }
        }

        if (resultant === "on") {
          const resultantScale = 2.8 * rho * (gFactor + 0.05);
          const rColor = "#8a0f9b";
          this.bR.create("arrow", [[C[0] - resultantScale * pressureDir2[0], C[1] - resultantScale * pressureDir2[1]], [C[0], C[1]]], {
            strokeColor: rColor,
            fillColor: rColor,
            strokeWidth: 5,
            fixed: true
          });

          const lfStart = [OX + 0.9, OY - 0.6];
          this.bR.create("segment", [[OX, OY], lfStart], {
            strokeColor: "#111",
            strokeWidth: 2,
            dash: 2,
            fixed: true
          });
          this.bR.create("arrow", [lfStart, [C[0] + 0.05, C[1] + 0.1]], {
            strokeColor: "#111",
            fillColor: "#111",
            strokeWidth: 2,
            fixed: true
          });
          this.bR.create("text", [(lfStart[0] + C[0]) / 2 - 0.1, (lfStart[1] + C[1]) / 2 + 0.5, "l_F"], {
            fontSize: 24,
            fixed: true
          });

          const cp = [cx + wx * 0.5, cy + wy * 0.5];
          this.bR.create("arrow", [[cp[0] - 0.95 * resultantScale * pressureDir3[0], cp[1] - 0.95 * resultantScale * pressureDir3[1]], [cp[0], cp[1]]], {
            strokeColor: rColor,
            fillColor: rColor,
            strokeWidth: 5,
            fixed: true
          });

          const Lnum = 20;
          const wnum = 10;
          const gnum = gVal;
          const zc = zA + 0.5 * Lnum * Math.sin(rad);
          const F = rho * 1000 * gnum * zc * wnum * Lnum;
          const sci = F === 0 ? "0" : F.toExponential(2).replace("e+", "x10^");
          this.bR.create("text", [-15.3, -10.2, `F = rho g zc w L = ${sci}`], {
            fontSize: 22,
            fixed: true,
            color: "#111"
          });
          this.bR.create("text", [4.2, -10.2, "Width: w = 10"], {
            fontSize: 22,
            fixed: true,
            color: "#111"
          });
          this.bR.create("text", [10.2, -10.2, "Length: L = 20"], {
            fontSize: 22,
            fixed: true,
            color: "#111"
          });
        }
      } else if (panel === "curved_const") {
        const c0 = [-8.3, 1.7 - 0.08 * zA];
        const R = 4.7;
        const rNum = 5;
        const wNum = 10;
        const thetaC = rad;
        const phi0 = Math.PI * 0.92 + rad * 0.5;
        const phi1 = Math.PI * 1.5 + rad * 0.5;
        const pts2d = [];
        for (let i = 0; i <= arrowCount; i++) {
          const t = i / arrowCount;
          const phi = phi0 + t * (phi1 - phi0);
          pts2d.push([c0[0] + R * Math.cos(phi), c0[1] + R * Math.sin(phi)]);
        }

        for (let i = 0; i < pts2d.length - 1; i++) {
          this.bR.create("segment", [pts2d[i], pts2d[i + 1]], {
            strokeColor: "#4f5cff",
            strokeWidth: 4,
            fixed: true
          });
        }

        this.bR.create("text", [pts2d[0][0] - 0.6, pts2d[0][1] + 0.3, "A"], { fontSize: 24, fixed: true });

        if (resultant === "off") {
          for (let i = 0; i < arrowCount; i++) {
            const p = pts2d[i];
            const inward = [c0[0] - p[0], c0[1] - p[1]];
            const norm = Math.hypot(inward[0], inward[1]) || 1;
            const d = [inward[0] / norm, inward[1] / norm];
            const len = (0.65 + 0.15 * i) * arrowScale;
            this.bR.create("arrow", [[p[0] + len * d[0], p[1] + len * d[1]], [p[0], p[1]]], {
              strokeColor: "red",
              fillColor: "red",
              strokeWidth: 2,
              fixed: true
            });
          }
        }

        const rc = [6.7, -0.9 - 0.12 * shiftZ];
        const rR = 2.5;
        const wx = -1.25;
        const wy = 1.72;
        const rib = [];
        for (let i = 0; i <= arrowCount; i++) {
          const t = i / arrowCount;
          const phi = phi0 + t * (phi1 - phi0);
          const p = [rc[0] + rR * Math.cos(phi), rc[1] + rR * Math.sin(phi)];
          rib.push(p);
        }

        for (let i = 0; i < rib.length - 1; i++) {
          const a1 = rib[i];
          const a2 = rib[i + 1];
          const b2 = [a2[0] + wx, a2[1] + wy];
          const b1 = [a1[0] + wx, a1[1] + wy];
          const r1 = this.bR.create("point", a1, { visible: false, fixed: true, name: "" });
          const r2 = this.bR.create("point", a2, { visible: false, fixed: true, name: "" });
          const r3 = this.bR.create("point", b2, { visible: false, fixed: true, name: "" });
          const r4 = this.bR.create("point", b1, { visible: false, fixed: true, name: "" });
          this.bR.create("polygon", [r1, r2, r3, r4], {
            fillColor: "#01a7e0",
            fillOpacity: 0.78,
            borders: { strokeColor: "#333", strokeWidth: 1.2 },
            vertices: { visible: false },
            fixed: true
          });
        }

        if (resultant === "off") {
          for (let i = 1; i < rib.length - 1; i++) {
            const p = [rib[i][0] + 0.52 * wx, rib[i][1] + 0.52 * wy];
            const inward = [rc[0] + 0.52 * wx - p[0], rc[1] + 0.52 * wy - p[1]];
            const n = Math.hypot(inward[0], inward[1]) || 1;
            const d = [inward[0] / n, inward[1] / n];
            const len = (0.5 + 0.1 * i) * arrowScale;
            this.bR.create("arrow", [[p[0] + len * d[0], p[1] + len * d[1]], [p[0], p[1]]], {
              strokeColor: "red",
              fillColor: "red",
              strokeWidth: 2,
              fixed: true
            });
          }
        }

        if (resultant === "on") {
          const rColor = "#8a0f9b";
          const cMid = pts2d[Math.floor(pts2d.length * 0.52)];
          const d2 = [c0[0] - cMid[0], c0[1] - cMid[1]];
          const n2 = Math.hypot(d2[0], d2[1]) || 1;
          const u2 = [d2[0] / n2, d2[1] / n2];
          const s = 2.8 * rho * (gFactor + 0.05);
          this.bR.create("arrow", [[cMid[0] + s * u2[0], cMid[1] + s * u2[1]], cMid], {
            strokeColor: rColor,
            fillColor: rColor,
            strokeWidth: 5,
            fixed: true
          });

          const pointA = [c0[0] + 1.15 * R, c0[1] + 0.95 * R];
          this.bR.create("point", pointA, {
            fixed: true,
            size: 2,
            strokeColor: "#111",
            fillColor: "#111",
            name: ""
          });
          this.bR.create("text", [pointA[0] + 0.35, pointA[1] - 0.05, "A"], {
            fontSize: 24,
            fixed: true
          });
          this.bR.create("segment", [[OX, pointA[1]], pointA], {
            strokeColor: "#222",
            dash: 2,
            strokeWidth: 2,
            fixed: true
          });
          this.bR.create("segment", [pointA, cMid], {
            strokeColor: "#222",
            dash: 2,
            strokeWidth: 2,
            fixed: true
          });
          this.bR.create("text", [pointA[0] - 1.65, pointA[1] - 0.85, "β"], {
            fontSize: 24,
            fixed: true
          });

          const pMid = rib[Math.floor(rib.length * 0.56)];
          const p3 = [pMid[0] + 0.5 * wx, pMid[1] + 0.5 * wy];
          const d3 = [rc[0] + 0.5 * wx - p3[0], rc[1] + 0.5 * wy - p3[1]];
          const n3 = Math.hypot(d3[0], d3[1]) || 1;
          const u3 = [d3[0] / n3, d3[1] / n3];
          this.bR.create("arrow", [[p3[0] + 0.95 * s * u3[0], p3[1] + 0.95 * s * u3[1]], p3], {
            strokeColor: rColor,
            fillColor: rColor,
            strokeWidth: 5,
            fixed: true
          });

          const Fx = -rhoSI * gVal * wNum * rNum * (zA * (Math.cos(thetaC) - Math.sin(thetaC)) + 0.5 * rNum * Math.cos(2 * thetaC));
          const Fz = rhoSI * gVal * wNum * rNum * (zA * (Math.sin(thetaC) + Math.cos(thetaC)) + 0.25 * rNum * (Math.PI + 2 * Math.sin(2 * thetaC)));

          this.bR.create("text", [-15.5, -10.0, `F_x = -rho g w r [z_A(cosθ-sinθ)+0.5r cos2θ] = ${Fx.toExponential(2)}`], {
            fontSize: 20,
            fixed: true,
            color: "#111"
          });
          this.bR.create("text", [-15.5, -11.1, `F_z = rho g w r [z_A(sinθ+cosθ)+0.25r(π+2sin2θ)] = ${Fz.toExponential(2)}`], {
            fontSize: 20,
            fixed: true,
            color: "#111"
          });
        }
      } else {
        const A = [-10.6, -2.1 - 0.08 * zA];
        const L = 5.8;
        const thetaV = rad * 0.7;
        const B = [A[0] + L * Math.cos(thetaV), A[1] - L * Math.sin(thetaV)];
        const C = [(A[0] + B[0]) / 2, (A[1] + B[1]) / 2];
        this.bR.create("segment", [A, B], {
          strokeColor: "#4f5cff",
          strokeWidth: 4,
          fixed: true
        });
        this.bR.create("text", [C[0] - 0.35, C[1] - 0.6, "A"], { fontSize: 24, fixed: true });

        const t2 = [Math.cos(thetaV), -Math.sin(thetaV)];
        const n2 = [-t2[1], t2[0]];
        const pressureDir2 = [-n2[0], -n2[1]];
        if (resultant === "off") {
          for (let i = 0; i < arrowCount; i++) {
            const t = (i + 0.2) / arrowCount;
            const px = A[0] + t * (B[0] - A[0]);
            const py = A[1] + t * (B[1] - A[1]);
            const widthGain = 0.78 + 0.55 * (1 - Math.pow(2 * t - 1, 2));
            const len = (0.8 + 0.35 * widthGain) * arrowScale;
            this.bR.create("arrow", [[px - len * pressureDir2[0], py - len * pressureDir2[1]], [px, py]], {
              strokeColor: "red",
              fillColor: "red",
              strokeWidth: 2,
              fixed: true
            });
          }
        }

        const sc = [6.2, -3.45 - 0.06 * shiftZ];
        const sLen = 1.72;
        const s0 = [sc[0] - sLen * Math.cos(thetaV), sc[1] + sLen * Math.sin(thetaV)];
        const s1 = [sc[0] + sLen * Math.cos(thetaV), sc[1] - sLen * Math.sin(thetaV)];
        const wv = [-1.25, 1.1];
        const strips = 14;
        const topPts = [];
        const botPts = [];
        for (let i = 0; i <= strips; i++) {
          const t = i / strips;
          const bx = s0[0] + t * (s1[0] - s0[0]);
          const by = s0[1] + t * (s1[1] - s0[1]);
          const k = 0.8 + 1.1 * (1 - Math.pow(2 * t - 1, 2));
          topPts.push([bx + 0.5 * k * wv[0], by + 0.5 * k * wv[1]]);
          botPts.push([bx - 0.5 * k * wv[0], by - 0.5 * k * wv[1]]);
        }

        for (let i = 0; i < strips; i++) {
          const a1 = topPts[i];
          const a2 = topPts[i + 1];
          const b2 = botPts[i + 1];
          const b1 = botPts[i];
          const m1 = this.bR.create("point", a1, { visible: false, fixed: true, name: "" });
          const m2 = this.bR.create("point", a2, { visible: false, fixed: true, name: "" });
          const m3 = this.bR.create("point", b2, { visible: false, fixed: true, name: "" });
          const m4 = this.bR.create("point", b1, { visible: false, fixed: true, name: "" });
          this.bR.create("polygon", [m1, m2, m3, m4], {
            fillColor: "#ffe4a8",
            fillOpacity: 0.72,
            borders: { strokeColor: "#333", strokeWidth: 1.4 },
            vertices: { visible: false },
            fixed: true
          });
        }

        if (resultant === "off") {
          const t3 = [s1[0] - s0[0], s1[1] - s0[1]];
          const n3n = Math.hypot(-t3[1], t3[0]) || 1;
          const pressureDir3 = [t3[1] / n3n, -t3[0] / n3n];
          for (let i = 0; i < strips; i++) {
            const t = (i + 0.2) / strips;
            const px = s0[0] + t * (s1[0] - s0[0]);
            const py = s0[1] + t * (s1[1] - s0[1]);
            const len = (0.7 + 0.3 * (1 - Math.pow(2 * t - 1, 2))) * arrowScale;
            this.bR.create("arrow", [[px - len * pressureDir3[0], py - len * pressureDir3[1]], [px, py]], {
              strokeColor: "red",
              fillColor: "red",
              strokeWidth: 2,
              fixed: true
            });
          }
        }

        if (resultant === "on") {
          const rColor = "#8a0f9b";
          const s = 2.8 * rho * (gFactor + 0.05);
          this.bR.create("arrow", [[C[0] - s * pressureDir2[0], C[1] - s * pressureDir2[1]], [C[0], C[1]]], {
            strokeColor: rColor,
            fillColor: rColor,
            strokeWidth: 5,
            fixed: true
          });

          const dFEnd = [C[0] - 1.15 * pressureDir2[0], C[1] - 1.15 * pressureDir2[1]];
          this.bR.create("arrow", [dFEnd, C], {
            strokeColor: "#111",
            fillColor: "#111",
            strokeWidth: 3,
            fixed: true
          });
          this.bR.create("segment", [C, [C[0] + 1.25 * pressureDir2[1], C[1] - 1.25 * pressureDir2[0]]], {
            strokeColor: "red",
            strokeWidth: 3,
            fixed: true
          });
          this.bR.create("text", [C[0] + 0.25, C[1] - 1.35, "d_F"], {
            fontSize: 24,
            fixed: true
          });

          const cp = [(s0[0] + s1[0]) / 2, (s0[1] + s1[1]) / 2];
          const t3 = [s1[0] - s0[0], s1[1] - s0[1]];
          const n3n = Math.hypot(-t3[1], t3[0]) || 1;
          const pressureDir3 = [t3[1] / n3n, -t3[0] / n3n];
          this.bR.create("arrow", [[cp[0] - 0.95 * s * pressureDir3[0], cp[1] - 0.95 * s * pressureDir3[1]], [cp[0], cp[1]]], {
            strokeColor: rColor,
            fillColor: rColor,
            strokeWidth: 5,
            fixed: true
          });

          this.bR.create("segment", [[cp[0] - 1.8, cp[1] + 0.75], [cp[0] + 1.8, cp[1] - 0.75]], {
            strokeColor: "#111",
            strokeWidth: 2,
            dash: 2,
            fixed: true
          });
          this.bR.create("segment", [[cp[0] - 0.3, cp[1] + 1.4], [cp[0] + 0.3, cp[1] - 1.4]], {
            strokeColor: "#111",
            strokeWidth: 2,
            dash: 2,
            fixed: true
          });

          const rNum = 5;
          const area = Math.PI * rNum * rNum;
          const F = rhoSI * gVal * zA * area;
          const dF = 0.04 + 0.03 * Math.abs(Math.sin(thetaV));
          this.bR.create("text", [-15.5, -10.0, `F = rho g z_A A = rho g z_A π r^2 = ${F.toExponential(2)}`], {
            fontSize: 22,
            fixed: true,
            color: "#111"
          });
          this.bR.create("text", [-15.5, -11.1, `d_F = M / F ≈ ${dF.toFixed(2)}`], {
            fontSize: 22,
            fixed: true,
            color: "#111"
          });
          this.bR.create("text", [6.8, -10.0, "Radius: r = 5"], {
            fontSize: 22,
            fixed: true,
            color: "#111"
          });
        }
      }

      this.bR.unsuspendUpdate();
    }
  }
};
</script>

