<template>
  <div class="container-fluid">
    <div class="row my-3 justify-content-center">
      <div id="boxLeft" class="boxLeft my-2" style="width:700px; height:360px;"></div>

      <div id="boxRight" class="boxRight my-2" style="width:700px; height:700px;"></div>
    </div>
  </div>
</template>

<script>
import { InputHandler } from "../../../classes/InputHandler.js";
export default {
  components: {},
  data: () => {
    return {
      sliders: {},
      IH: undefined,
      bL: undefined,
      bR: undefined,
      animState: null,
      supportButtons: {},
      movementButtons: [],
      momentLabel: undefined,
      momentButtons: []
    };
  },
  mounted() {
    // Setup left board for controls only.
    const bL = JXG.JSXGraph.initBoard("boxLeft", {
      boundingbox: [-15, 12, 15, -14],
      keepAspectRatio: true,
      showCopyright: false,
      pan: { enabled: false },
      zoom: { wheel: false },
      showNavigation: false,
      showZoom: false,
      axis: false
    });
    bL.resizeContainer(700, 360);

    const bR = JXG.JSXGraph.initBoard("boxRight", {
      boundingbox: [-4.5, 4.5, 4.5, -4.5],
      keepAspectRatio: true,
      showCopyright: false,
      pan: { enabled: false },
      zoom: { wheel: false },
      showNavigation: false,
      showZoom: false,
      axis: false
    });
    bR.resizeContainer(700, 700);

    this.bL = bL;
    this.bR = bR;

    let sliders = {};
    this.sliders = sliders;
    const LABEL_SIZE = 18;

    const INTERVAL = -3.0;
    const TOP_Y = 9;
    const LEFT_X = -3.2;
    const RIGHT_X = 7.8;

    const INITIAL_VALUES = {
      support: "pinned",
      reactive: "off",
      moment: "off",
      movement: "play"
    };
    let IH = new InputHandler(bL, INTERVAL, TOP_Y, LEFT_X, RIGHT_X, LABEL_SIZE, INITIAL_VALUES, 0);
    this.IH = IH;

    for (let data of [
      [false, "Support Type", INTERVAL * 0.5, false],
      ["force", "Magnitude of force", INTERVAL * 1.8, true, [0, 0.81, 2], [0], "#1f77b4"],
      ["phi", "Angle of force  :  \u03d5(\u00b0)", INTERVAL * 2.9, true, [-180, 45, 180], [0], "#1f77b4"],
      ["theta", "Angle of bar  :  \u03b8(\u00b0)", INTERVAL * 4.0, true, [0, 90, 180], [0], "#1f77b4"],
      ["reactive", "Reactive force", INTERVAL * 5.25, false, ["On", "on", "Off", "off"], [0]],
      [false, "Show Movement", INTERVAL * 6.45, false]
    ]) {
      IH.generate(data, sliders);
    }

    // Three-option support selector (radio-like behavior).
    const supportButtonY = TOP_Y + INTERVAL * 0.5;
    const supportOptions = [
      { key: "pinned", label: "Pinned Joint", x: -3.2 },
      { key: "cantilever", label: "Cantilever Beam", x: 3.8 },
      { key: "roller", label: "Roller Supporter", x: 13.2 }
    ];

    supportOptions.forEach(opt => {
      const btn = bL.create(
        "button",
        [
          opt.x,
          supportButtonY,
          opt.label,
          () => {
            IH.values.support = opt.key;
            this.updateSupportButtonStyles();
            this.updateSupportDependentControls();
            IH.fixTextAlignment();
            IH.toggleButtons();
          }
        ],
        { fixed: true }
      );
      btn.rendNodeButton.classList.add("btn-primary");
      this.supportButtons[opt.key] = btn;
    });

    // Compact movement controls for left panel only.
    const movementY = TOP_Y + INTERVAL * 6.45;

    // Animation state — plain mutable object shared via closure.
    // effectiveTheta / netMoment / animTick are defined after barLength/rad below;
    // the callbacks here only *call* them at click-time, so no TDZ issues.
    const animState = { offset: 0, playing: false, timer: null };
    this.animState = animState;
    let animTick; // assigned after barLength is defined

    const movementButtonDefs = [
      {
        key: "play",
        label: "\u25b6",
        x: LEFT_X,
        onClick: () => {
          if (animState.playing) {
            clearInterval(animState.timer);
            animState.timer = null;
            animState.playing = false;
            IH.values.movement = "paused";
          } else {
            animState.playing = true;
            animState.timer = setInterval(animTick, 1000 / 30);
            IH.values.movement = "play";
          }
          this.updateMovementButtonStyles();
        }
      },
      {
        key: "reset",
        label: "|\u25c1",
        x: LEFT_X + 2.0,
        onClick: () => {
          clearInterval(animState.timer);
          animState.timer = null;
          animState.playing = false;
          animState.offset = 0;
          IH.values.movement = "reset";
          this.updateMovementButtonStyles();
          bR.fullUpdate();
        }
      },
      {
        key: "up",
        label: "\u226b",
        x: LEFT_X + 4.2,
        onClick: () => {
          animState.offset += 0.15;
          IH.values.movement = "up";
          this.updateMovementButtonStyles();
          bR.fullUpdate();
        }
      },
      {
        key: "down",
        label: "\u226a",
        x: LEFT_X + 6.4,
        onClick: () => {
          animState.offset -= 0.15;
          IH.values.movement = "down";
          this.updateMovementButtonStyles();
          bR.fullUpdate();
        }
      }
    ];

    movementButtonDefs.forEach(spec => {
      const btn = bL.create(
        "button",
        [spec.x, movementY, spec.label, spec.onClick],
        { fixed: true }
      );
      btn.rendNodeButton.classList.add("btn-primary");
      this.movementButtons.push({ key: spec.key, btn });
    });

    // Moment controls for cantilever case.
    const reactiveY = TOP_Y + INTERVAL * 5.25;
    this.momentLabel = bL.create("text", [6.3, reactiveY, "Moment"], {
      fontSize: LABEL_SIZE,
      fixed: true
    });
    const momentSpecs = [
      { key: "on", label: "On", x: 10.6 },
      { key: "off", label: "Off", x: 13.2 }
    ];
    momentSpecs.forEach(spec => {
      const btn = bL.create(
        "button",
        [
          spec.x,
          reactiveY,
          spec.label,
          () => {
            IH.values.moment = spec.key;
            this.updateMomentButtonStyles();
            IH.fixTextAlignment();
          }
        ],
        { fixed: true }
      );
      btn.rendNodeButton.classList.add("btn-primary");
      this.momentButtons.push({ key: spec.key, btn });
    });

    // Small nudges to resemble the screenshot spacing.
    sliders.force.setAttribute({ snapWidth: 0.01 });
    sliders.phi.setAttribute({ snapWidth: 1 });
    sliders.theta.setAttribute({ snapWidth: 1 });

    const rad = deg => (deg * Math.PI) / 180;
    const barLength = 3;
    const forceScale = 0.9;

    // Effective beam angle: slider value + animation rotation offset (degrees).
    const effectiveTheta = () => sliders.theta.Value() + (180 / Math.PI) * animState.offset;

    // Net moment about pivot = L * F * sin(theta_eff - phi).
    // Cantilever with both reactive force and moment on → zero (equilibrium, no rotation).
    const netMoment = () => {
      if (
        IH.values.support === "cantilever" &&
        IH.values.reactive === "on" &&
        IH.values.moment === "on"
      ) {
        return 0;
      }
      return barLength * sliders.force.Value() * Math.sin(rad(effectiveTheta() - sliders.phi.Value()));
    };

    animTick = () => {
      animState.offset += netMoment() * 0.8 * (1 / 30);
      bR.fullUpdate();
    };

    const supportIs = key => () => IH.values.support === key;
    const pinnedVisible = supportIs("pinned");
    const cantileverVisible = supportIs("cantilever");
    const rollerVisible = supportIs("roller");
    const thetaIsZero = () => Math.abs(effectiveTheta()) < 0.5;
    const rollerBaseVisible = () => rollerVisible() && !thetaIsZero();
    const reactiveOn = () => IH.values.reactive === "on";
    const momentOn = () => IH.values.moment === "on";
    const reactivePinnedVisible = () => reactiveOn() && pinnedVisible();
    const reactiveCantileverVisible = () => reactiveOn() && cantileverVisible();
    const reactiveRollerVisible = () => reactiveOn() && rollerVisible();
    const cantileverMomentVisible = () => reactiveOn() && cantileverVisible() && momentOn();

    // Right panel frame and ticks.
    const frameStyle = {
      straightFirst: false,
      straightLast: false,
      fixed: true,
      strokeWidth: 2,
      strokeColor: "#8b8b8b"
    };
    const frameBottom = bR.create("line", [[-4, -4], [4, -4]], frameStyle);
    const frameTop = bR.create("line", [[-4, 4], [4, 4]], frameStyle);
    const frameLeft = bR.create("line", [[-4, -4], [-4, 4]], frameStyle);
    const frameRight = bR.create("line", [[4, -4], [4, 4]], frameStyle);

    bR.create("ticks", [frameBottom, 1], {
      drawLabels: true,
      drawZero: false,
      includeBoundaries: true,
      fixed: true,
      minorTicks: 3,
      label: { fontSize: 16 }
    });
    bR.create("ticks", [frameTop, 1], {
      drawLabels: false,
      includeBoundaries: true,
      fixed: true,
      minorTicks: 3
    });
    bR.create("ticks", [frameLeft, 1], {
      drawLabels: true,
      drawZero: false,
      includeBoundaries: true,
      fixed: true,
      minorTicks: 3,
      label: { fontSize: 16 }
    });
    bR.create("ticks", [frameRight, 1], {
      drawLabels: false,
      includeBoundaries: true,
      fixed: true,
      minorTicks: 3
    });

    const pivotX = 0;
    const pivotY = 0;
    const beamEndX = () => pivotX + barLength * Math.cos(rad(effectiveTheta()));
    const beamEndY = () => pivotY + barLength * Math.sin(rad(effectiveTheta()));

    // Define force angle so phi=0 points to the left, matching the original panel behavior.
    const forceTipX = () => beamEndX() - forceScale * sliders.force.Value() * Math.cos(rad(sliders.phi.Value()));
    const forceTipY = () => beamEndY() - forceScale * sliders.force.Value() * Math.sin(rad(sliders.phi.Value()));

    // For cantilever and roller, reactive force direction follows bar normal.
    // This guarantees an upward arrow when theta=0.
    const reactiveLen = () => forceScale * sliders.force.Value();
    const normalX = () => -Math.sin(rad(effectiveTheta()));
    const normalY = () => Math.cos(rad(effectiveTheta()));
    const pinnedReactionTipX = () => pivotX + reactiveLen() * normalX();
    const pinnedReactionTipY = () => pivotY + reactiveLen() * normalY();
    const cantileverReactionTipX = () => pivotX + reactiveLen() * normalX();
    const cantileverReactionTipY = () => pivotY + reactiveLen() * normalY();
    const rollerReactionTipX = () => pivotX + reactiveLen() * normalX();
    const rollerReactionTipY = () => pivotY + reactiveLen() * normalY();

    // Beam + force are common for all support types.
    bR.create("point", [pivotX, pivotY], {
      name: "",
      size: 6,
      fixed: true,
      strokeColor: "#00aa00",
      fillColor: "#00cc00",
      visible: true
    });

    bR.create(
      "segment",
      [
        [pivotX, pivotY],
        [
          () => beamEndX(),
          () => beamEndY()
        ]
      ],
      {
        strokeWidth: 18,
        strokeColor: "#6d73ff",
        fixed: true,
        visible: true
      }
    );

    bR.create(
      "segment",
      [
        [pivotX, pivotY],
        [
          () => beamEndX(),
          () => beamEndY()
        ]
      ],
      {
        dash: 2,
        strokeWidth: 2,
        strokeColor: "#444",
        fixed: true,
        visible: true
      }
    );

    bR.create(
      "arrow",
      [
        [
          () => beamEndX(),
          () => beamEndY()
        ],
        [
          () => forceTipX(),
          () => forceTipY()
        ]
      ],
      {
        strokeWidth: 4,
        strokeColor: "#ff0000",
        fillColor: "#ff0000",
        fixed: true,
        visible: true
      }
    );

    // Pinned support symbol.
    const baseY = -0.45;
    bR.create("segment", [[-0.35, baseY], [0.35, baseY]], {
      strokeWidth: 5,
      strokeColor: "#00aa00",
      fixed: true,
      visible: pinnedVisible
    });
    for (let x = -0.3; x <= 0.25; x += 0.15) {
      bR.create("segment", [[x, baseY], [x - 0.08, baseY - 0.12]], {
        strokeWidth: 3,
        strokeColor: "#00aa00",
        fixed: true,
        visible: pinnedVisible
      });
    }

    // Cantilever support symbol.
    bR.create("segment", [[0, -0.4], [0, 0.4]], {
      strokeWidth: 5,
      strokeColor: "#111",
      fixed: true,
      visible: cantileverVisible
    });
    for (let y = -0.35; y <= 0.3; y += 0.12) {
      bR.create("segment", [[0, y], [-0.22, y - 0.1]], {
        strokeWidth: 3,
        strokeColor: "#111",
        fixed: true,
        visible: cantileverVisible
      });
    }

    // Roller support symbol.
    bR.create("polygon", [[0, 0], [-0.22, -0.35], [0.22, -0.35]], {
      borders: {
        strokeColor: "#00aa00",
        strokeWidth: 4,
        fixed: true,
        visible: rollerBaseVisible
      },
      fillColor: "#00cc00",
      fillOpacity: 0.8,
      vertices: {
        visible: false
      },
      fixed: true,
      visible: rollerBaseVisible
    });
    [-0.16, 0, 0.16].forEach(x => {
      bR.create("circle", [[x, -0.41], 0.05], {
        strokeColor: "#00aa00",
        fillColor: "#00cc00",
        strokeWidth: 2,
        fixed: true,
        visible: rollerBaseVisible
      });
    });
    bR.create("segment", [[-0.3, -0.5], [0.3, -0.5]], {
      strokeWidth: 4,
      strokeColor: "#00aa00",
      fixed: true,
      visible: rollerBaseVisible
    });

    bR.create("text", [-0.9, 0.7, () => "Pinned joint view"], {
      fontSize: 16,
      fixed: true,
      visible: pinnedVisible
    });

    bR.create("text", [-1.15, 0.7, () => "Cantilever beam view"], {
      fontSize: 16,
      fixed: true,
      visible: cantileverVisible
    });

    bR.create("text", [-0.95, 0.7, () => "Roller supporter view"], {
      fontSize: 16,
      fixed: true,
      visible: rollerVisible
    });

    // Cantilever resisting moment symbol (enabled by Moment: On).
    bR.create(
      "curve",
      [
        t => pivotX + 0.55 * Math.cos(t),
        t => pivotY + 0.55 * Math.sin(t),
        () => rad(210),
        () => rad(90)
      ],
      {
        strokeWidth: 4,
        strokeColor: "#1d2cff",
        fixed: true,
        visible: cantileverMomentVisible
      }
    );
    bR.create(
      "arrow",
      [
        [
          () => pivotX + 0.12,
          () => pivotY + 0.55
        ],
        [
          () => pivotX - 0.12,
          () => pivotY + 0.46
        ]
      ],
      {
        strokeWidth: 3,
        strokeColor: "#1d2cff",
        fillColor: "#1d2cff",
        fixed: true,
        visible: cantileverMomentVisible
      }
    );
    bR.create("text", [() => pivotX - 0.75, () => pivotY - 0.1, "M"], {
      fontSize: 32,
      color: "#1d2cff",
      fixed: true,
      visible: cantileverMomentVisible
    });

    // Reactive force arrows shown when the toggle is on.
    bR.create(
      "arrow",
      [
        [pivotX, pivotY],
        [
          () => cantileverReactionTipX(),
          () => cantileverReactionTipY()
        ]
      ],
      {
        strokeWidth: 4,
        strokeColor: "#111",
        fillColor: "#111",
        fixed: true,
        visible: reactivePinnedVisible
      }
    );

    bR.create(
      "arrow",
      [
        [pivotX, pivotY],
        [
          () => pinnedReactionTipX(),
          () => pinnedReactionTipY()
        ]
      ],
      {
        strokeWidth: 4,
        strokeColor: "#111",
        fillColor: "#111",
        fixed: true,
        visible: reactiveCantileverVisible
      }
    );

    bR.create(
      "arrow",
      [
        [pivotX, pivotY],
        [
          () => rollerReactionTipX(),
          () => rollerReactionTipY()
        ]
      ],
      {
        strokeWidth: 4,
        strokeColor: "#111",
        fillColor: "#111",
        fixed: true,
        visible: reactiveRollerVisible
      }
    );

    // Keep right panel synced while sliders are being dragged.
    ["force", "phi"].forEach(key => {
      sliders[key].on("drag", () => {
        bR.fullUpdate();
      });
    });
    // Dragging theta resets the animation and updates the view.
    sliders.theta.on("drag", () => {
      clearInterval(animState.timer);
      animState.timer = null;
      animState.playing = false;
      animState.offset = 0;
      IH.values.movement = "paused";
      this.updateMovementButtonStyles();
      bR.fullUpdate();
    });

    let prevSupport = IH.values.support;
    IH.setCallback(() => {
      // Reset animation whenever the support type changes.
      if (IH.values.support !== prevSupport) {
        prevSupport = IH.values.support;
        clearInterval(animState.timer);
        animState.timer = null;
        animState.playing = false;
        animState.offset = 0;
        IH.values.movement = "paused";
      }
      this.updateSupportDependentControls();
      this.updateSupportButtonStyles();
      this.updateMovementButtonStyles();
      this.updateMomentButtonStyles();
      this.bL.fullUpdate();
      this.bR.fullUpdate();
    });

    // Init visual states.
    this.updateSupportDependentControls();
    this.updateSupportButtonStyles();
    this.updateMovementButtonStyles();
    this.updateMomentButtonStyles();
    IH.fixTextAlignment();
    IH.toggleButtons();
    bR.fullUpdate();
    this.changeState(0);
  },
  methods: {
    setBtnActive(btn, active) {
      if (!btn || !btn.rendNodeButton) return;
      btn.rendNodeButton.classList.toggle("btn-warning", active);
    },
    updateSupportButtonStyles() {
      if (!this.IH) return;
      const selected = this.IH.values.support;
      Object.keys(this.supportButtons).forEach(key => {
        this.setBtnActive(this.supportButtons[key], key === selected);
      });
    },
    updateMovementButtonStyles() {
      if (!this.IH) return;
      const selected = this.IH.values.movement;
      this.movementButtons.forEach(item => {
        this.setBtnActive(item.btn, item.key === selected);
      });
    },
    updateMomentButtonStyles() {
      if (!this.IH) return;
      const selected = this.IH.values.moment;
      this.momentButtons.forEach(item => {
        this.setBtnActive(item.btn, item.key === selected);
      });
    },
    updateSupportDependentControls() {
      const { sliders, IH } = this;
      if (!IH || !sliders.theta) return;

      const thetaEnabled = true;
      sliders.theta.setAttribute({ visible: thetaEnabled });

      // theta row has slider textbox+button in InputHandler objects map.
      ["theta1", "theta2"].forEach(key => {
        const entry = IH.objectsToEnable[key];
        if (!entry || !entry.object || !entry.object[entry.component]) return;
        entry.object[entry.component].disabled = !thetaEnabled;
        entry.object[entry.component].style.display = thetaEnabled ? "" : "none";
      });

      // Slider DOM node is available after rendering.
      if (sliders.theta.rendNode && sliders.theta.rendNode.style) {
        sliders.theta.rendNode.style.display = thetaEnabled ? "" : "none";
      }

      const showMomentControls = IH.values.support === "cantilever";
      if (this.momentLabel && this.momentLabel.rendNode && this.momentLabel.rendNode.style) {
        this.momentLabel.rendNode.style.display = showMomentControls ? "" : "none";
      }
      this.momentButtons.forEach(item => {
        if (item.btn && item.btn.rendNodeButton) {
          item.btn.rendNodeButton.style.display = showMomentControls ? "" : "none";
        }
      });
    },
    changeState(newState) {
      this.IH.updateState(newState);
    }
  },
  beforeDestroy() {
    if (this.animState && this.animState.timer) {
      clearInterval(this.animState.timer);
    }
  }
};
</script>

<style>
button:disabled {
  opacity: 0.5;
  /* visibility: hidden; */
}
input:disabled {
  opacity: 0.7;
  /* visibility: hidden; */
}
</style>
